var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"또 무슨 난리래? 침식체라도 나타났나?","JPN":"何だ？　また侵食体でも現れたのか？","ENG":"What's going on? Is there another C.O. attack?","TWN":"又在吵什麼？出現侵蝕體嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"경찰들 하는 얘기를 들었는데 용병들이 총격전을 벌였대. 한동안 잠잠하더니 또 이러네.","JPN":"警察の話を聞いたんだけど、傭兵が銃撃戦をしたんだって。しばらく大人しいと思ったらまたこれだ。","ENG":"I heard the cops talking and it seems like the mercenaries had a gunfight. Can't believe they're starting this again.","TWN":"聽警察說是傭兵發生槍戰，我才想說這陣子安靜不少，結果又來啦！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"거기 찍지 마세요! 찍으시면 안 됩니다!","JPN":"そこ、撮らないでください！　撮影は禁止です！","ENG":"Hey! You're not allowed to film this! Stop filming!","TWN":"請不要拍照，這裡不能拍照！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"옆 건물들도 붕괴될 수 있습니다! 사건 현장에 접근하지 말아 주세요!","JPN":"隣の建物も崩壊する可能性があります！　事件現場に近づかないでください！","ENG":"Please step away from the crime scene! It's not safe, the neighboring building may collapse as well!","TWN":"旁邊的建築物也可能會倒塌！請勿靠近案發現場！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"비키세요. 제 4 특별기동수사대에서 나온 이유미 경정입니다.","JPN":"どきなさい。第4特別機動捜査隊のカスカベ・ユミ警視です。","ENG":"Out of my way. I'm Major Lee Yumi of SWAT 4.","TWN":"請讓讓，我是第四特遣機動隊的李悠美警正。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 경정님. 마음 급하신 건 알지만 같은 공무원끼리 사이 좋게 지내야죠.","JPN":"はは、警視様。急いでいるのはわかりますけど、同じ公務員同士、仲良くしないと。","ENG":"Ha ha, Major! I know you're pressed for time, but you should get along with the other civil servants, too.","TWN":"哈哈，警正，我知道你很心急，但大家都是吃公家飯的，對人家客氣一點嘛～"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"담당하고 있는 실종 사건 때문에 왔어요. 여기서 일어난 폭발이랑 관련이 있어서요.","JPN":"担当している失踪事件で来ました。ここで発生した爆発と関係がありますので。","ENG":"I'm only here because of a missing persons case I'm working on. It seems as if the explosion here has some connection to it.","TWN":"我們是來調查一起失蹤案件的，與這裡發生的爆炸事件有關。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"크흠……. 어린 것이 까칠해선…….","JPN":"こほん……小娘のくせに可愛げがないな……","ENG":"Ahem...! Well aren't you a tiny little brat...","TWN":"咳咳……年紀輕輕說話沒大沒小的……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"건물은 아직 추가 붕괴 위험이 있습니다. 따라오세요.","JPN":"建物はまだ二次的な崩壊の危険性があります。ついてきてください。","ENG":"The building might be at risk of further collapse. Please follow me.","TWN":"大樓還有倒塌的危險，跟我來。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"그런데 실종자가 누구길래 4기동이 담당하는 겁니까?","JPN":"ところで、第4機動隊が担当するなんて、どんな失踪者なんですか？","ENG":"But who could the missing person be if SWAT 4 is on the case?","TWN":"不過失蹤的人是誰？竟然請到第四機動隊出馬。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"베로니카라는 이름의 여성입니다.","JPN":"ベロニカという名前の女性です。","ENG":"A woman named Veronica.","TWN":"是一位名叫貝洛妮卡的女性。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스라는 가사도우미 파견 업체의 사장이죠.","JPN":"フローラメイドサービスという家事代行派遣企業の社長です。","ENG":"She is the head of a housekeeping agency called Flora Maid Service.","TWN":"是一間名叫芙蘿拉女僕服務公司的家事幫手派遣業者的社長。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"직원 분이 이 근처에서 헤어졌는데 귀가하지 않았다고 해서 경찰에 신고했어요.","JPN":"職員の方が、この辺りで別れたのに帰ってこないと言って警察に通報したんですよ。","ENG":"One of her employee said she last saw her here, but when she didn't show up back home, she called the cops.","TWN":"員工說在這附近和她分開後，她一直沒回家，所以來報警。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>보통 사람은 메이드장님에게 못 당하지 말임다!</color> 라고 하는 바람에 저희 쪽으로 사건이 이관됐죠.","JPN":"<color=#ffd34c>普通の人間はメイド長に勝てないっす！</color>と言ったせいで、私たちの方に事件が移管されました。","ENG":"We were put on this case after the employee said, <color=#ffd34c>\\"A normal person can't hurt Chief Maid, ma'am!\\"</color>","TWN":"<color=#ffd34c>普通人才打不過女僕長咧！</color>因為報案人這樣說，所以案子就轉到我們手上囉。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"애 말을 믿다니 제정신인지 모르겠어.","JPN":"子どもの話を信じるなんて、頭がどうかしてるわ。","ENG":"I can't believe that you really trust what a child said.","TWN":"真不知道腦袋在想什麼，竟然相信一個孩子說的話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하여튼 매스컴에 관심 끌 때만 추켜세우지, 우릴 잡일꾼으로 보는 건 그대로라니까.","JPN":"まったく、マスコミの関心を引こうって時だけ大々的にするけど、私たちを雑用係程度としか考えていないのは相変わらずよね。","ENG":"Anyway, we're only being praised to attract the attention of the media. The rest of the time, our position isn't that different.","TWN":"總之只有媒體關注時才會吹捧我們，大家一樣把我們當成是打雜的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};